// from index.js
async function acquireLease(shardId, ownerId) {
  for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
    try {
      await ddb.update({
        TableName: LEASE_TABLE,
        Key: { shard_id: shardId },
        UpdateExpression: 'SET owner_id = :owner, expires_at = :exp',
        ConditionExpression: 'attribute_not_exists(owner_id) OR expires_at < :now',
        ExpressionAttributeValues: { ':owner': ownerId, ':exp': now + LEASE_TTL_SECONDS, ':now': now }
      }).promise();
      return true;
    } catch (err) {
      if (err.code === 'ConditionalCheckFailedException') {
        await sleep(RETRY_INTERVAL_MS);  // <-- fixed interval, no jitter, no backoff
        continue;
      }
      throw err;
    }
  }
  throw new Error('lease acquire timeout');
}
